import{_ as a,o as i,c as o,a2 as t}from"./chunks/framework.BWuWLRhz.js";const h=JSON.parse(`{"title":"Product roadmap","description":"See Sovereign's product direction by outcome, without confusing plans with shipped features.","frontmatter":{"title":"Product roadmap","description":"See Sovereign's product direction by outcome, without confusing plans with shipped features.","aside":false},"headers":[],"relativePath":"product-roadmap.md","filePath":"product-roadmap.md"}`),r={name:"product-roadmap.md"};function n(l,e,s,d,c,p){return i(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="product-roadmap" tabindex="-1">Product roadmap <a class="header-anchor" href="#product-roadmap" aria-label="Permalink to &quot;Product roadmap&quot;">​</a></h1><p>This page describes product direction, not a delivery guarantee. Horizons can change as designs are reviewed and implementation constraints become clearer. For technical proposals, use the <a href="/rfcs/README.html">RFC index</a>. Contributors can use the source repository&#39;s <code>roadmap.md</code> and <code>epics/</code> for canonical engineering task status. This page intentionally summarizes outcomes instead of duplicating that queue.</p><h2 id="available-now" tabindex="-1">Available now <a class="header-anchor" href="#available-now" aria-label="Permalink to &quot;Available now&quot;">​</a></h2><ul><li>A self-hostable, multi-user workspace runtime.</li><li>Shared authentication, account security, and administrative controls.</li><li>Launcher, Account, and Console workspace apps.</li><li>Sovereign Tasks, Sovereign Shopper, and Sovereign Plainwrite as first-party apps composed with the platform.</li><li>A plugin SDK boundary, app-scoped databases, and shared design system.</li><li>Docker and non-Docker deployment guidance.</li></ul><h2 id="being-built" tabindex="-1">Being built <a class="header-anchor" href="#being-built" aria-label="Permalink to &quot;Being built&quot;">​</a></h2><ul><li>Stronger operator backup, recovery, and data-control workflows.</li><li>Broader plugin capabilities for storage, jobs, events, tools, and external connections.</li><li>More complete device and installed-app experiences.</li><li>Sovereign Wallet Phase 1 for loyalty and membership card workflows.</li><li>Clearer user, operator, and app-developer documentation.</li></ul><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h2><ul><li>Easier production operation and upgrade confidence.</li><li>A more discoverable app ecosystem and compatibility story.</li><li>Richer controls for groups and app access.</li><li>Additional privacy-preserving platform services for apps.</li></ul><h2 id="later" tabindex="-1">Later <a class="header-anchor" href="#later" aria-label="Permalink to &quot;Later&quot;">​</a></h2><ul><li>Expanded desktop and mobile shells around a self-hosted instance.</li><li>Purpose-specific apps that demonstrate the runtime beyond administration.</li><li>More complete portability between compatible Sovereign deployments.</li></ul><h2 id="exploring" tabindex="-1">Exploring <a class="header-anchor" href="#exploring" aria-label="Permalink to &quot;Exploring&quot;">​</a></h2><ul><li>Client-side encryption foundations for sensitive app data.</li><li>Peer-to-peer chat with separate chat identity and transport.</li><li>Local-first assistant and orchestration experiences.</li></ul><p><strong>Exploring does not mean committed.</strong> Draft RFCs are design inputs and may be changed, phased, or withdrawn.</p>',13)])])}const m=a(r,[["render",n]]);export{h as __pageData,m as default};
